sql:
SELECT sponsor_name, description
FROM sponsors
WHERE sponsor_id = 1;

SELECT status
FROM event_participants
WHERE event_id = 0 AND player_id = 1;

SELECT player_name
FROM players
ORDER BY ranking, player_name;

SELECT mode_name
FROM modes
WHERE mode_id = 1;

SELECT COUNT(*) AS total_streams
FROM streaming
WHERE event_id = 1;
